NOTICE_VERSIONS = {
    # version: tuple of changes that invalidate prior consent
    "v2.0": [],
    "v2.1": [],        # minor clarifications — existing consent valid
    "v2.2": ["scope:conversation_history"],   # new scope added — re-capture required
    "v2.3": ["retention_period", "model_upgrade"],  # material change — re-capture required
}

CURRENT_VERSION = "v2.3"
MATERIAL_CHANGES_SINCE = {
    "v2.0": True,
    "v2.1": True,
    "v2.2": True,
    "v2.3": False,
}

def consent_needs_refresh(record: "ConsentRecord") -> bool:
    """Return True if the stored consent was given under an old version
    that had a material change since, requiring re-capture."""
    return MATERIAL_CHANGES_SINCE.get(record.consent_version, True)
